const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');
const app = express();

// Create a write stream for logging
const logStream = fs.createWriteStream(path.join(__dirname, 'access.log'), { flags: 'a' });

// Custom token to log username, IP, and custom headers
morgan.token('user', (req) => {
  const username = req.headers['x-username'] || 'anonymous';
  return `User: ${sanitize(username)}`;
});

morgan.token('ip', (req) => {
  return `IP: ${sanitize(req.ip)}`;
});

morgan.token('custom-header', (req) => {
  const customHeader = req.headers['x-custom-header'] || 'none';
  return `Custom-Header: ${sanitize(customHeader)}`;
});

// Sanitize input to prevent log injection
function sanitize(input) {
  return input.replace(/[\n\r]/g, '');
}

// Setup morgan to use the custom format
app.use(morgan(':method :url :status :res[content-length] - :response-time ms :user :ip :custom-header', { stream: logStream }));

app.use(express.json());

app.post('/data', (req, res) => {
  const userData = req.body.data;
  logStream.write(`User Data: ${sanitize(userData)}\n`);
  res.send('Data received and logged');
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});